import React, { useState, useMemo } from "react";
import { Card, Typography, theme, Row, Col, Empty } from "antd";
import { SensorData } from "../data/mockData";
import EChart from "@/framework/components/Chart/EChart";

const { Text, Title } = Typography;
const { useToken } = theme;

function SensorSplitCard({ sensor }: { sensor: SensorData }) {
  const { token } = useToken();
  const [focusedPart, setFocusedPart] = useState<"GAUGE" | "BAR" | null>(null);

  const gaugeFlex = focusedPart === "GAUGE" ? 2.5 : (focusedPart === "BAR" ? 0.6 : 1);
  const barFlex = focusedPart === "BAR" ? 2.5 : (focusedPart === "GAUGE" ? 0.6 : 1);

  // ECharts Gauge Option
  const gaugeOption = useMemo(() => ({
    series: [
      {
        type: 'gauge',
        startAngle: 180,
        endAngle: 0,
        center: ['50%', '75%'],
        radius: '110%',
        min: 0,
        max: 60,
        progress: {
          show: true,
          width: 8,
          itemStyle: { color: sensor.value > 40 ? token.colorError : token.colorPrimary }
        },
        pointer: { show: false },
        axisLine: { lineStyle: { width: 8, color: [[1, token.colorFillTertiary]] } },
        axisTick: { show: false },
        splitLine: { show: false },
        axisLabel: { show: false },
        anchor: { show: false },
        title: { show: false },
        detail: {
          valueAnimation: true,
          offsetCenter: [0, -10],
          fontSize: focusedPart === "GAUGE" ? 24 : 18,
          fontWeight: 'bold',
          formatter: '{value}',
          color: token.colorText
        },
        data: [{ value: Number(sensor.value.toFixed(2)) }]
      }
    ]
  }), [sensor.value, token, focusedPart]);

  // ECharts Trend Option
  const trendOption = useMemo(() => ({
    grid: { left: 5, right: 5, top: 10, bottom: 5, containLabel: false },
    xAxis: {
      type: 'category',
      data: sensor.history.map(p => p.time),
      show: false
    },
    yAxis: { type: 'value', show: false, max: 60 },
    series: [{
      data: sensor.history.map(p => p.value),
      type: 'bar',
      itemStyle: {
        color: sensor.value > 40 ? token.colorError : (focusedPart === "BAR" ? token.colorPrimary : token.colorTextDisabled),
        borderRadius: [2, 2, 0, 0]
      },
      emphasis: { itemStyle: { color: token.colorPrimary } }
    }],
    tooltip: { show: focusedPart === "BAR" }
  }), [sensor, token, focusedPart]);

  return (
    <Card
      hoverable
      style={{
        height: "100%",
        background: token.colorBgContainer,
        borderColor: token.colorBorderSecondary,
        transition: "all 0.4s ease",
        overflow: "hidden"
      }}
      styles={{ 
        body: { 
          padding: "12px", 
          height: "100%", 
          display: "flex", 
          flexDirection: "column",
          gap: 8
        }
      }}
      onMouseLeave={() => setFocusedPart(null)}
    >
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 2 }}>
        <Text strong style={{ fontSize: 13, color: token.colorTextSecondary }}>{sensor.name}</Text>
        <div style={{ background: sensor.value > 40 ? token.colorError : token.colorSuccess, width: 6, height: 6, borderRadius: "50%" }} />
      </div>

      <div 
        onMouseEnter={() => setFocusedPart("GAUGE")}
        style={{ 
          flex: gaugeFlex, 
          display: "flex", 
          flexDirection: "column",
          justifyContent: "center", 
          alignItems: "center",
          transition: "all 0.5s cubic-bezier(0.4, 0, 0.2, 1)",
          background: focusedPart === "GAUGE" ? `${token.colorPrimary}08` : "transparent",
          borderRadius: 8,
          position: "relative",
          overflow: "hidden"
        }}
      >
        <EChart option={gaugeOption} style={{ height: "100%", width: "100%" }} />
        <div style={{ position: "absolute", bottom: "15%", fontSize: 10, color: token.colorTextDescription }}>{sensor.unit}</div>
      </div>

      <div 
        onMouseEnter={() => setFocusedPart("BAR")}
        style={{ 
          flex: barFlex,
          display: "flex",
          flexDirection: "column",
          background: focusedPart === "BAR" ? `${token.colorPrimary}08` : `${token.colorFillTertiary}33`,
          borderRadius: 8,
          transition: "all 0.5s cubic-bezier(0.4, 0, 0.2, 1)",
          padding: "4px 8px",
          overflow: "hidden",
          justifyContent: "flex-end"
        }}
      >
        <EChart option={trendOption} style={{ height: "100%", width: "100%" }} />
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 2 }}>
          <Text style={{ fontSize: 8, color: token.colorTextDescription }}>{sensor.history[0]?.time}</Text>
          {focusedPart === "BAR" && <Text strong style={{ fontSize: 9, color: token.colorPrimary }}>24H TREND</Text>}
          <Text style={{ fontSize: 8, color: token.colorTextDescription }}>{sensor.history[sensor.history.length-1]?.time}</Text>
        </div>
      </div>
    </Card>
  );
}

interface SensorChartViewProps {
  sensors: SensorData[];
}

export default function SensorChartView({ sensors }: SensorChartViewProps) {
  const { token } = useToken();

  if (!sensors || sensors.length === 0) {
    return <Empty style={{ marginTop: 100 }} description="선택된 공장에 센서 데이터가 없습니다." />;
  }

  return (
    <div style={{ padding: 0, background: token.colorBgContainer, height: "100%", overflow: "hidden", display: "flex", flexDirection: "column" }}>
      <div style={{ padding: "8px 16px", display: "flex", justifyContent: "space-between", alignItems: "center", borderBottom: `1px solid ${token.colorBorderSecondary}44`, background: token.colorBgContainer }}>
        <Title level={4} style={{ margin: 0, fontSize: 16 }}>실시간 센서 정밀 분석</Title>
        <Text type="secondary" style={{ fontSize: 12 }}>Last Update: {new Date().toLocaleTimeString()}</Text>
      </div>
      <div style={{ flex: 1, padding: 8 }}>
        <Row gutter={[8, 8]} style={{ height: "100%" }}>
          {sensors.map((sensor) => (
            <Col xs={24} sm={12} md={8} lg={6} key={sensor.id} style={{ height: "calc(50% - 4px)" }}>
              <SensorSplitCard sensor={sensor} />
            </Col>
          ))}
        </Row>
      </div>
    </div>
  );
}
