import React, { useMemo } from "react";
import { Card, Typography, theme } from "antd";
import EChart from "@/framework/components/Chart/EChart";

import * as echarts from "echarts";

const { Title } = Typography;
const { useToken } = theme;

interface SensorGaugeCardProps {
  name: string;
  value: number;
  unit: string;
}

export default function SensorGaugeCard({
  name,
  value,
  unit,
}: SensorGaugeCardProps) {
  const { token } = useToken();

  const gaugeOption = useMemo(() => ({
    series: [
      {
        type: 'gauge',
        startAngle: 190,
        endAngle: -10,
        center: ['50%', '65%'],
        radius: '100%',
        min: 0,
        max: 60,
        progress: {
          show: true,
          width: 4,
          itemStyle: { color: value > 40 ? token.colorError : token.colorPrimary }
        },
        pointer: { show: false },
        axisLine: { lineStyle: { width: 4, color: [[1, token.colorFillTertiary]] } },
        axisTick: { show: false },
        splitLine: { show: false },
        axisLabel: { show: false },
        detail: {
          offsetCenter: [0, 0],
          fontSize: 16,
          fontWeight: 'bold',
          formatter: '{value}',
          color: token.colorText
        },
        data: [{ value: Number(value.toFixed(1)) }]
      }
    ]
  }), [value, token]);

  const sparklineOption = useMemo(() => ({
    grid: { left: 0, right: 0, top: 0, bottom: 0 },
    xAxis: { type: 'category', show: false },
    yAxis: { type: 'value', show: false, max: 60 },
    tooltip: { show: false },
    series: [{
      data: [30, 50, 45, 60, 55, 40, 35, 42], // Mock sparkline
      type: 'line',
      smooth: true,
      symbol: 'none',
      lineStyle: { width: 1, color: token.colorPrimary },
      areaStyle: {
        color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
          { offset: 0, color: `${token.colorPrimary}44` },
          { offset: 1, color: `${token.colorPrimary}00` }
        ])
      }
    }]
  }), [token]);

  return (
    <Card
      size="small"
      style={{
        flex: 1,
        background: token.colorBgContainer,
        border: `1px solid ${token.colorBorderSecondary}`,
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
      }}
      styles={{ body: { textAlign: "center", padding: "6px 4px", width: "100%", height: "100%", display: "flex", flexDirection: "column" } }}
    >
      <Title level={5} style={{ fontSize: 11, marginBottom: 2, marginTop: 0, color: token.colorText }}>{name}</Title>

      <div style={{ flex: 1, width: "100%", position: "relative" }}>
        <EChart option={gaugeOption} style={{ height: 80, width: "100%" }} />
        <div style={{ position: "absolute", bottom: "10%", left: 0, right: 0, fontSize: 8, color: token.colorTextDescription }}>{unit}</div>
      </div>

      <div style={{ height: 24, width: "100%", marginTop: 4 }}>
        <EChart option={sparklineOption} style={{ height: "100%", width: "100%" }} />
      </div>
    </Card>
  );
}
