import React, { useMemo } from "react";
import { theme, Typography } from "antd";
import { CameraInfo } from "../data/mockData";
import { useCameraMockSync, getCameraImgUrl } from "../hooks/useCameraMock";

const { Text } = Typography;
const { useToken } = theme;

interface CameraGridProps {
  cameras: CameraInfo[];
  layoutCount: number;
  startIndex: number;
  onDoubleClickCamera: (index: number) => void;
}

export default function CameraGrid({
  cameras,
  layoutCount = 4,
  startIndex = 0,
  onDoubleClickCamera,
}: CameraGridProps) {
  const { token } = useToken();
  const globalFrame = useCameraMockSync(2); // Global 2 FPS sync timer

  const cams = useMemo(() => {
    return cameras.slice(startIndex, startIndex + layoutCount);
  }, [cameras, startIndex, layoutCount]);

  // layoutCount에 따라 정방형 그리드 행/열 계산
  let grid = 1;
  if (layoutCount <= 1) grid = 1;
  else if (layoutCount <= 4) grid = 2;
  else if (layoutCount <= 9) grid = 3;
  else grid = 4;

  // 렌더링 분리: 각 카메라 셀을 반환
  function renderCameraCell(cam: CameraInfo, idx: number) {
    const imgUrl = getCameraImgUrl(cam.id, globalFrame);

    return (
      <div
        key={cam.id}
        onDoubleClick={() => onDoubleClickCamera(startIndex + idx)}
        style={{
          position: "relative",
          background: "#000",
          border: cam.hasAlarm
            ? `3px solid ${token.colorError}`
            : `1px solid ${token.colorBorderSecondary}`,
          borderRadius: token.borderRadius,
          overflow: "hidden",
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          cursor: "pointer",
          transition: "all 0.2s ease",
          userSelect: "none",
          WebkitUserSelect: "none",
          MozUserSelect: "none",
          msUserSelect: "none",
          backgroundImage: imgUrl ? `url(${imgUrl})` : "none",
          backgroundSize: "cover",
          backgroundPosition: "center",
          minHeight: 80,
          minWidth: 120,
          width: "100%",
          height: "100%",
        }}
        className="camera-card-hover"
      >
        {/* Camera Name Label */}
        <div
          style={{
            position: "absolute",
            top: 8,
            left: 12,
            zIndex: 10,
            background: "rgba(0, 0, 0, 0.6)",
            padding: "2px 10px",
            borderRadius: 4,
            border: "1px solid rgba(255,255,255,0.1)",
          }}
        >
          <Text style={{ fontSize: 12, color: "#fff", fontWeight: "bold" }}>
            {cam.name}
          </Text>
        </div>

        {/* Alarm Overlay */}
        {cam.hasAlarm && (
          <div
            style={{
              position: "absolute",
              top: 8,
              right: 12,
              zIndex: 10,
              background: token.colorError,
              padding: "2px 8px",
              borderRadius: 4,
              animation: "blink 1s infinite",
            }}
          >
            <Text style={{ fontSize: 11, color: "white", fontWeight: "bold" }}>
              검지 알람
            </Text>
          </div>
        )}

        {/* NO SIGNAL Overlay (if image fails) */}
        {!imgUrl && (
          <div
            style={{
              position: "absolute",
              color: "rgba(255,255,255,0.2)",
              fontSize: 20,
              fontWeight: "bold",
              letterSpacing: 2,
            }}
          >
            NO SIGNAL
          </div>
        )}

        {/* Flicker-free Preloader */}
        <img
          src={getCameraImgUrl(cam.id, globalFrame + 1)}
          style={{ display: "none" }}
          alt="preloader"
        />
      </div>
    );
  }

  return (
    <div
      className="camera-grid-responsive"
      style={{
        display: "grid",
        gridTemplateColumns: `repeat(${grid}, 1fr)`,
        gridTemplateRows: `repeat(${grid}, 1fr)`,
        gap: "min(1vw, 12px)",
        height: "100%",
        minWidth: "320px",
        overflow: "auto",
        padding: "min(2vw, 12px)",
        background: token.colorBgContainer,
      }}
    >
      <style>{`
        .camera-card-hover:hover {
          filter: brightness(1.1);
          box-shadow: inset 0 0 10px rgba(255,255,255,0.1);
        }
        @keyframes blink {
          0% { opacity: 1; }
          50% { opacity: 0.5; }
          100% { opacity: 1; }
        }
      `}</style>

      {cams.map((cam, i) => renderCameraCell(cam, i))}
    </div>
  );
}
