import React from "react";
import { Timeline, Typography, Card, Button, theme } from "antd";
import {
  WarningOutlined,
  InfoCircleOutlined,
  SyncOutlined,
} from "@ant-design/icons";
import { EventInfo } from "../data/mockData";

import { useI18n } from "@/framework/i18n/hooks";

const { Text } = Typography;
const { useToken } = theme;

interface EventTimelineProps {
  events: EventInfo[];
  onEventSelect?: (event: EventInfo) => void;
  onRefresh?: () => void;
}

export default function EventTimeline({
  events,
  onEventSelect,
  onRefresh,
}: EventTimelineProps) {
  const { token } = useToken();
  const { t } = useI18n(["dashboard"]);

  return (
    <Card
      title={t("sections.timeline")}
      extra={
        <Button
          type="text"
          icon={<SyncOutlined />}
          onClick={() => onRefresh && onRefresh()}
        />
      }
      style={{
        height: "100%",
        display: "flex",
        flexDirection: "column",
        background: token.colorBgContainer,
        border: "none",
        minHeight: 0,
      }}
      bodyStyle={{ flex: 1, overflowY: "auto", padding: "16px 8px" }}
    >
      <Timeline
        mode="start"
        items={events.map((event) => {
          const color =
            event.type === "ALARM"
              ? token.colorError
              : event.type === "INFO"
              ? token.colorInfo
              : token.colorTextDisabled;
          const icon =
            event.type === "ALARM" ? (
              <WarningOutlined
                style={{ fontSize: 16, color: token.colorError }}
              />
            ) : (
              <InfoCircleOutlined
                style={{ fontSize: 16, color: token.colorInfo }}
              />
            );

          return {
            color,
            icon,
            content: (
              <div
                className="timeline-item-container"
                onClick={() => onEventSelect && onEventSelect(event)}
                role="button"
                tabIndex={0}
                onKeyDown={(e) => {
                  if (e.key === "Enter" || e.key === " ")
                    onEventSelect && onEventSelect(event);
                }}
                style={{
                  padding: "8px 16px",
                  borderRadius: 8,
                  cursor: "pointer",
                  transition: "all 0.3s cubic-bezier(0.4, 0, 0.2, 1)",
                  border: `1px solid transparent`,
                  position: "relative",
                  width: "calc(100% - 10px)",
                }}
              >
                <div style={{ marginBottom: 4 }}>
                  <Text strong style={{ fontSize: 13, color: token.colorText }}>
                    {event.time}
                  </Text>
                </div>
                <div
                  style={{ display: "flex", flexDirection: "column", gap: 2 }}
                >
                  <Text strong style={{ fontSize: 14, color: token.colorText }}>
                    {event.title}
                  </Text>
                  <div
                    style={{
                      display: "flex",
                      justifyContent: "space-between",
                      alignItems: "center",
                    }}
                  >
                    <Text
                      style={{ fontSize: 11, color: token.colorTextSecondary }}
                    >
                      Plant #{event.plantId}
                    </Text>
                    <Text
                      style={{
                        fontSize: 11,
                        color: token.colorTextDescription,
                      }}
                    >
                      ID: {event.id}
                    </Text>
                  </div>
                </div>
              </div>
            ),
          };
        })}
      />

      <style>{`
        .timeline-item-container:hover {
          background-color: ${token.colorFillAlter};
          border-color: ${token.colorBorderSecondary} !important;
          box-shadow: ${token.boxShadowTertiary};
          transform: translateX(4px);
        }
        .timeline-item-container:hover .ant-typography {
          color: ${token.colorPrimary} !important;
        }
      `}</style>
    </Card>
  );
}
